const express = require('express');
const app = express();
const Redis = require('ioredis');
const redis = new Redis({
  host: 'localhost',
  port: 6379,
});
const twilio = require('twilio');

// Twilio account settings
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// Redis expiration time in minutes
const EXPIRATION_TIME = 10;

app.use(express.json());

async function generateCode() {
  const code = Math.floor(Math.random() * 1000000).toString().padStart(6, '0');
  return code;
}

async function sendCode(phoneNumber) {
  const code = await generateCode();
  const message = `Your verification code is: ${code}`;
  const from = '+1234567890';
  const to = phoneNumber;

  try {
    const result = await client.messages
      .create({
        body: message,
        from,
        to,
      })
      .then((message) => console.log(message.sid));

    return code;
  } catch (error) {
    console.error(error);
    throw error;
  }
}

async function storeCode(phoneNumber, code) {
  const key = `mfa-code:${phoneNumber}`;
  await redis.set(key, code, 'EX', EXPIRATION_TIME * 60); // Set expiration time in seconds
}

app.post('/verify', async (req, res) => {
  const { phoneNumber, code } = req.body;

  try {
    const storedCode = await redis.get(`mfa-code:${phoneNumber}`);
    if (!storedCode) {
      return res.status(401).send({ message: 'Invalid code' });
    }

    if (code !== storedCode) {
      const attempts = await redis.incr(`attempts:${phoneNumber}`);
      if (attempts >= 10) {
        await redis.set(`locked:${phoneNumber}`, true, 'EX', EXPIRATION_TIME * 60);
        return res.status(401).send({ message: 'Too many attempts. Account locked.' });
      }
    }

    if (code === storedCode) {
      await redis.del(`mfa-code:${phoneNumber}`);
      await redis.set(`locked:${phoneNumber}`, false, 'EX', EXPIRATION_TIME * 60);
      return res.status(200).send({ message: 'Access granted' });
    } else {
      return res.status(401).send({ message: 'Invalid code' });
    }
  } catch (error) {
    console.error(error);
    return res.status(500).send({ message: 'Internal Server Error' });
  }
});

